wifi_businesses = []

for b in businesses:
    attrs = b.get('attributes')
    desc = b.get('description', '')

    has_wifi = False
    if isinstance(attrs, dict) and 'WiFi' in attrs:
        wifi_val = str(attrs['WiFi']).lower()
        if 'free' in wifi_val or 'paid' in wifi_val:
            has_wifi = True

    if has_wifi:
        # Extract state
        match = re.search(r" in [^,]+,\s+([A-Z]{2})", desc)
        state = None
        if match:
            state = match.group(1)
        else:
            match = re.search(r" ([A-Z]{2}) location", desc)
            if match:
                state = match.group(1)
            else:
                match = re.search(r",\s+([A-Z]{2})", desc)
                if match:
                    state = match.group(1)

        if state:
            wifi_businesses.append(state)

state_counts = Counter(wifi_businesses)

print("__RESULT__:")
